(function registerIlBronzaDatatablesSummary() {
    if (!$.fn.dataTable || !$.fn.dataTable.Api) {
        setTimeout(registerIlBronzaDatatablesSummary, 100);
        return;
    }

    /* ===============================
     *  API helpers (unchanged)
     * =============================== */
    $.fn.dataTable.Api.register('hasSummary()', function (table = null) {
        return this.getDataAttribute('summary', table);
    });

    $.fn.dataTable.Api.register('hasSummaryActive()', function () {
        const table = this.table().node();
        return table && table.__summaryActive === true;
    });

    $.fn.dataTable.Api.register('toggleShowSelected()', function (table = null) {
        if (!table) table = this.getTableElement();
        if (typeof table.data('showSelected') === 'undefined')
            return table.data('showSelected', true);
        table.data('showSelected', !table.data('showSelected'));
    });

    window.transformDataBySummaryExistence = function (tableId, summary, json) {
        return json.data;
    };

    /* ===============================
     *  Value extraction
     * =============================== */

    function rawToString(raw) {
        if (raw === null || typeof raw === 'undefined') return null;

        if (Array.isArray(raw)) {
            if (raw.length > 1) return rawToString(raw[1]);
            return rawToString(raw[0]);
        }

        if (typeof raw === 'string') {
            const trimmed = raw.trim();
            return trimmed === '' ? null : trimmed;
        }

        return null;
    }

    /**
     * Scan from the right: two digits, then a non-digit symbol → decimal separator.
     * E.g. "53.851,30" → ",", "53851.30" → "."
     */
    function detectDecimalSeparator(str) {
        const s = String(str).trim();
        if (s.length < 3) return null;

        const lastTwo = s.slice(-2);
        if (!/^\d{2}$/.test(lastTwo)) return null;

        const sep = s.charAt(s.length - 3);
        if (sep === '-' || /\d/.test(sep)) return null;

        return sep;
    }

    function detectNumberFormat(str) {
        const decimalSep = detectDecimalSeparator(str);
        if (!decimalSep) return null;

        const s = String(str).trim();
        let thousandsSep = null;

        for (let i = 0; i < s.length; i++) {
            const c = s.charAt(i);
            if (c !== decimalSep && c !== '-' && !/\d/.test(c) && c !== ' ') {
                thousandsSep = c;
                break;
            }
        }

        return {
            decimalSep,
            thousandsSep,
            fractionDigits: 2
        };
    }

    function detectNumberFormatFromRaw(raw) {
        const str = rawToString(raw);
        if (!str) return null;

        return detectNumberFormat(str);
    }

    function completeNumberFormatForDisplay(format) {
        if (!format || !format.decimalSep) {
            return format;
        }

        if (!format.thousandsSep && format.decimalSep === ',') {
            format.thousandsSep = '.';
        }

        if (!format.thousandsSep && format.decimalSep === '.') {
            format.thousandsSep = ',';
        }

        return format;
    }

    function detectColumnNumberFormat(rows, columnIndex, useSearchApplied) {
        let detected = null;

        rows.every(function (rowIdx) {
            const raw = useSearchApplied
                ? this.cell(rowIdx, columnIndex, { search: 'applied' }).data()
                : this.cell(rowIdx, columnIndex).data();

            const format = detectNumberFormatFromRaw(raw);
            if (format === null) {
                return true;
            }

            if (!detected) {
                detected = {
                    decimalSep: format.decimalSep,
                    thousandsSep: format.thousandsSep,
                    fractionDigits: format.fractionDigits
                };
            } else if (!detected.thousandsSep && format.thousandsSep) {
                detected.thousandsSep = format.thousandsSep;
            }

            return true;
        });

        return completeNumberFormatForDisplay(detected);
    }

    function parseWithDecimalSeparator(str, decimalSep) {
        let negative = false;
        let s = String(str).trim();

        if (s.startsWith('-')) {
            negative = true;
            s = s.slice(1).trim();
        }

        let normalized = '';
        for (let i = 0; i < s.length; i++) {
            const c = s.charAt(i);
            if (c >= '0' && c <= '9') {
                normalized += c;
            } else if (c === decimalSep) {
                normalized += '.';
            }
        }

        const v = parseFloat(normalized);
        if (isNaN(v)) return null;

        return negative ? -v : v;
    }

    function extractNumericValue(raw, decimalSep) {
        if (raw === null || typeof raw === 'undefined') return null;

        if (Array.isArray(raw)) {
            if (raw.length > 1) return extractNumericValue(raw[1], decimalSep);
            return extractNumericValue(raw[0], decimalSep);
        }

        if (typeof raw === 'number') {
            return isNaN(raw) ? null : raw;
        }

        if (typeof raw === 'string') {
            const trimmed = raw.trim();
            if (trimmed === '') return null;

            if (decimalSep) {
                return parseWithDecimalSeparator(trimmed, decimalSep);
            }

            const v = parseFloat(trimmed);
            return isNaN(v) ? null : v;
        }

        return null;
    }

    function handlerUsesLocaleNumberParse(handler) {
        return handler.format === 'number'
            && (handler.aggregate === 'sum' || handler.aggregate === 'average');
    }

    /* ===============================
     *  Aggregators
     * =============================== */

    const aggregators = {
        sum(values) {
            return values.reduce((acc, v) => acc + v, 0);
        },

        average(values) {
            if (!values.length) return 0;
            return values.reduce((acc, v) => acc + v, 0) / values.length;
        },

        distinct(values) {
            const map = {};
            values.forEach(v => {
                const key = String(v);
                map[key] = (map[key] || 0) + 1;
            });
            return map;
        },
        countDistinct(values) {
            const set = new Set(values.map(v => String(v)));
            return set.size;
        }
    };

    /* ===============================
     *  Formatters
     * =============================== */

    function formatLocalizedNumber(value, numberFormat) {
        const fractionDigits = numberFormat.fractionDigits ?? 2;
        const negative = value < 0;
        const absValue = Math.abs(value);
        const factor = Math.pow(10, fractionDigits);
        const rounded = Math.round((absValue + Number.EPSILON) * factor) / factor;

        let [intPart, fracPart] = rounded.toFixed(fractionDigits).split('.');

        if (numberFormat.thousandsSep) {
            intPart = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, numberFormat.thousandsSep);
        }

        let result = intPart;
        if (fractionDigits > 0) {
            result += numberFormat.decimalSep + fracPart;
        }

        return negative ? '-' + result : result;
    }

    const formatters = {
        number(value, numberFormat) {
            if (numberFormat && numberFormat.decimalSep) {
                return formatLocalizedNumber(value, numberFormat);
            }

            return Math.round((value + Number.EPSILON) * 100) / 100;
        },

        minutes(value) {
            const hours = Math.floor(value / 60) + 'h';
            const minutes = Math.floor(value % 60) + "'";
            return hours + ' ' + minutes;
        },

        distinct(map) {
            return Object.keys(map)
                .map(k => k + ': ' + map[k])
                .join('<br />');
        }
    };

    /* ===============================
     *  Summary dispatcher
     * =============================== */

    const summaryHandlers = {
        sum: {
            aggregate: 'sum',
            format: 'number'
        },
        average: {
            aggregate: 'average',
            format: 'number'
        },
        sumMinutes: {
            aggregate: 'sum',
            format: 'minutes'
        },
        sumMinutesArray: {
            aggregate: 'sum',
            format: 'minutes'
        },
        sumSecondsArray: {
            aggregate: 'sum',
            format: 'minutes',
            post(value) {
                return value / 60;
            }
        },
        sumSeconds: {
            aggregate: 'sum',
            format: 'minutes',
            post(value) {
                return value / 60;
            }
        },
        distinct: {
            aggregate: 'distinct',
            format: 'distinct'
        },
        countDistinct: {
            aggregate: 'countDistinct',
            format: 'number'
        }
    };

    /* ===============================
     *  Pure calculation helpers
     * =============================== */

    function calculateSummaryValues(rows, columnIndex, handler, useSearchApplied = false, numberFormat = null)
    {
        const values = [];
        const decimalSep = numberFormat ? numberFormat.decimalSep : null;

        rows.every(function (rowIdx) {
            const raw = useSearchApplied
                ? this.cell(rowIdx, columnIndex, { search: 'applied' }).data()
                : this.cell(rowIdx, columnIndex).data();

            const numeric = extractNumericValue(raw, decimalSep);
            if (numeric !== null) values.push(numeric);
        });

        let result = aggregators[handler.aggregate](values);
        if (handler.post)
            result = handler.post(result);

        return result;
    }

    function renderSummaryValue($target, value, handler, numberFormat = null)
    {
        const formatted = handler.format === 'number'
            ? formatters.number(value, numberFormat)
            : formatters[handler.format](value);

        $target
            .html(formatted)
            .addClass('summary-updated');

        setTimeout(function () {
            $target.removeClass('summary-updated');
        }, 500);
    }

    /* ===============================
     *  Main summary engine
     * =============================== */

    window.populateFilteredColumnValues = function (api, tableId = null) {
        if (!api.hasSummaryActive()) {
            return;
        }
        // React ONLY when summary is active
        if (!tableId) tableId = api.table().node().id;

        let filterRowsOptions = {};
        if (window[tableId + 'FilteredSelected'])
            filterRowsOptions = { selected: true };

        const summaryRows = api.rows({ selected: true }); // for 'summary' row
        const inlineRows = api.rows(); // for 'inlinesearchsummary' row

        $('#' + tableId)
            .find('thead tr.columns th')
            .each(function () {
                const summaryType = $(this).find('input').data('summary');
                if (!summaryType || !summaryHandlers[summaryType]) return;

                const columnIndex = $(this).data('column');

                // inline search summary (all filtered rows)
                const inlineTarget = $('#' + tableId + ' .inlinesearchsummary')
                    .find('.summary' + columnIndex);

                // selected-only summary
                const summaryTarget = $('#' + tableId + ' tr.summary')
                    .find('.summary' + columnIndex);

                const handler = summaryHandlers[summaryType];

                const numberFormat = handlerUsesLocaleNumberParse(handler)
                    ? (
                        detectColumnNumberFormat(inlineRows, columnIndex, true)
                        || detectColumnNumberFormat(summaryRows, columnIndex, false)
                    )
                    : null;

                const inlineResult = calculateSummaryValues(
                    inlineRows,
                    columnIndex,
                    handler,
                    true,
                    numberFormat
                );

                renderSummaryValue(inlineTarget, inlineResult, handler, numberFormat);

                const selectedResult = calculateSummaryValues(
                    summaryRows,
                    columnIndex,
                    handler,
                    false,
                    numberFormat
                );

                renderSummaryValue(summaryTarget, selectedResult, handler, numberFormat);
            });
    };

    /* ===============================
     *  Recalculate summary on row selection changes
     * =============================== */

    $(document).on('select.dt deselect.dt', function (e, dt) {
        if (!dt || !dt.hasSummaryActive || !dt.hasSummaryActive())
            return;

        // Lightweight recalculation: update summary without triggering a full draw
        window.populateFilteredColumnValues(dt);
    });
})();